mapper.select:
select count(*) from friend_request
where fromUserId = #{fromUserId}
and toUserId = #{toUserId}
and status = 0

mapper.update:
update friend_request
set status = #{status}
where requestId = #{requestId}

mapper.delete:
DELETE FROM friend_request
WHERE fromUserId = #{fromUserId}
AND toUserId = #{toUserId}
